import type GraphicOrigin from "./GraphicOrigin.js";
import type ImageryTileLayer from "../layers/ImageryTileLayer.js";

/**
 * Provides information about the [ImageryTileLayer](https://developers.arcgis.com/javascript/latest/references/core/layers/ImageryTileLayer/) from which a graphic originates.
 * You can access the graphic's origin through the graphic's [origin](https://developers.arcgis.com/javascript/latest/references/core/Graphic/#origin) property.
 *
 * @since 5.0
 * @example
 * // get a point from view's click event
 *  view.on("click", async (event) => {
 *    // Search for all features only on included layer at the clicked location
 *    const response = await view.hitTest(event, {include: layer});
 *    // if graphics are returned from layer, get the layer id from graphic origin
 *    if (response.results.length > 0) {
 *      const originId = response.results[0].graphic?.origin?.layer?.id;
 *    }
 *  });
 */
export default class ImageryTileGraphicOrigin extends GraphicOrigin {
  constructor(layer: ImageryTileLayer);
  /** A layer from which a graphic originates. */
  readonly layer: ImageryTileLayer;
  /**
   * Indicates the type of layer the graphic originated from.
   *
   * @default "imagery-tile"
   */
  readonly type: ImageryTileLayer["type"];
}